-- 1. Solicitors × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'solicitors',
  'web-design',
  'When someone needs a solicitor, they are typically dealing with one of the most significant events of their life: buying a home, going through a divorce, writing a will, defending against criminal charges, or pursuing compensation for an injury. They are anxious, often confused about the legal process, and acutely aware that choosing the wrong solicitor could have life-altering consequences. Your website must communicate competence, trustworthiness, and approachability simultaneously, which is a balance most law firm websites fail to achieve. The majority of solicitor websites fall into two traps: either they are stuffed with impenetrable legal jargon that intimidates potential clients, or they are so generic that a conveyancing firm looks identical to a criminal defence practice. A purpose-built solicitor website organises your practice areas into clear, accessible pages that explain what you do in language clients actually understand. It displays your SRA registration and regulatory compliance prominently, provides transparent fee information that the SRA now expects, showcases testimonials from clients in similar situations, and makes it effortless to book an initial consultation. We build law firm websites that satisfy SRA regulatory requirements for digital transparency while converting anxious visitors into booked consultations through clear practice area presentation, fee transparency, and trust signals that address the specific concerns of people navigating legal processes for the first time.',
  'The legal profession faces increasing pressure from the SRA to provide transparent pricing and accessible information online. The 2018 Transparency Rules require many law firms to publish pricing, service descriptions, and regulatory information on their websites. Beyond compliance, the practical reality is that potential clients now research solicitors online before making contact. A firm with a dated, uninformative website loses enquiries to competitors who present their services clearly and transparently, regardless of their actual legal expertise.',
  'We design solicitor websites around practice areas with SRA compliance built in. Each practice area page explains the legal process in accessible language, displays published fee information where required, and includes testimonials relevant to that service. SRA registration numbers, complaints procedures, and professional indemnity information are displayed as required by regulatory guidance.',
  '[{"title": "Practice area pages written in jargon that intimidates potential clients", "description": "Most people seeking a solicitor have never engaged one before. When they land on a practice area page written in dense legal terminology, they cannot understand what you actually do for them, how the process works, or what outcome they can expect. Confused visitors do not enquire; they leave and find a firm that explains things in plain English."}, {"title": "No fee transparency despite SRA regulatory expectations", "description": "The SRA Transparency Rules require many law firms to publish pricing information for specific services including conveyancing, probate, employment tribunals, and motoring offences. Firms that fail to publish this information are not only non-compliant but also lose potential clients who expect to understand costs before making contact. Fee opacity drives visitors to competitors who provide the pricing clarity they demand."}, {"title": "SRA registration and regulatory compliance information missing or hidden", "description": "Solicitors are required to display their SRA registration number, provide a link to the SRA register, include a complaints procedure, and publish details of their professional indemnity insurance. Many law firm websites either omit these details or bury them in footer text. Non-compliance risks regulatory action and misses the trust-building opportunity that visible regulation provides."}]',
  '[{"title": "Practice area pages with accessible language and clear process explanation", "description": "Every practice area has a dedicated page explaining the legal service in language clients understand. Conveyancing pages walk through the buying or selling process step by step. Divorce pages explain the timeline and what to expect. Each page addresses the emotional context of the client''s situation and provides the clarity that converts anxious visitors into consultation bookings."}, {"title": "SRA-compliant fee transparency and pricing display", "description": "Published fee information for services covered by the SRA Transparency Rules, presented in clear, accessible formats. Fixed fee services display total costs including disbursements and VAT. Hourly rate services provide realistic cost ranges and factors that affect pricing. This transparency satisfies regulatory requirements while building client trust through pricing honesty."}, {"title": "Regulatory compliance display and trust signal integration", "description": "SRA registration numbers with direct links to the SRA register are displayed prominently. Complaints procedures, professional indemnity details, and regulatory body logos are presented clearly without being hidden in footer text. Client testimonials, accreditation badges, and team qualification displays provide additional trust signals that reassure potential clients."}]',
  '[{"question": "How do you handle SRA Transparency Rules on a solicitor website?", "answer": "We build fee information displays that meet SRA requirements for the regulated services where pricing publication is mandatory. For conveyancing, probate, employment tribunal, motoring offences, immigration, and debt recovery, we create clear pricing sections with total costs, disbursement breakdowns, and realistic timescales. These displays are reviewed against current SRA guidance."}, {"question": "How do you make legal services accessible to people who have never used a solicitor?", "answer": "Every practice area page is written in plain English, explaining the legal process from the client''s perspective. We describe what happens at each stage, how long it takes, what the client needs to do, and what outcome they can expect. Legal terminology is explained in context. The goal is that someone with no legal knowledge understands exactly what you offer."}, {"question": "Can the website handle multiple practice areas without looking cluttered?", "answer": "Yes. We use clear navigation architecture that groups practice areas logically: property, family, wills and probate, personal injury, criminal defence, commercial, and employment. Each area has its own landing page with individual service pages beneath. Visitors find the specific legal service they need without navigating through irrelevant practice areas."}, {"question": "How important are client testimonials for a solicitor website?", "answer": "Extremely. People choosing a solicitor for a stressful legal matter want to know that others in their situation had a positive experience. Testimonials specific to each practice area provide this reassurance. A divorce client reading a testimonial from another divorce client builds confidence in a way that generic reviews cannot match."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Solicitors × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'solicitors',
  'seo',
  'Legal searches represent some of the most valuable local search traffic available. When someone searches for divorce solicitor near me, conveyancing solicitor Kent, or criminal defence lawyer Maidstone, they are actively seeking legal representation and will instruct a solicitor within days or weeks. The lifetime value of a single legal client can be substantial: a conveyancing instruction leads to wills, then probate, then perhaps family law referrals. Yet the legal SEO landscape is fiercely competitive, with national comparison directories, legal aid finders, and large multi-office firms dominating many search results. Local and regional law firms can compete by exploiting geographic specificity, practice area depth, and the local knowledge that national directories cannot replicate. Our SEO campaigns for solicitors target every practice area, every geographic modifier, and every client question that generates search volume in your area. We build authority through legal guides that demonstrate expertise, practice area pages optimised for specific service searches, and local content that establishes your firm as the definitive legal resource in your region. The compound effect of ranking across multiple practice areas creates a dominating local presence that national directories cannot match for firms committed to long-term SEO investment.',
  'The first page of Google results for solicitor searches is dominated by directories, comparison sites, and the largest law firms with dedicated marketing teams. Local firms without an SEO strategy are invisible to the majority of potential clients who search online before choosing a solicitor. Given that a single new client instruction can be worth hundreds or thousands of pounds in fees, and that clients often return for multiple legal matters over their lifetime, the revenue impact of poor search visibility is substantial.',
  'We build legal SEO campaigns around practice areas and geographic modifiers. Every service your firm offers gets dedicated, optimised content targeting the specific searches potential clients use. Legal guide content builds topical authority that improves rankings across all practice areas. Local pages target town and area-specific searches where your physical presence gives you a ranking advantage.',
  '[{"title": "Invisible for practice-area-specific searches in your local area", "description": "When a potential client searches for family solicitor Maidstone or conveyancing lawyer Canterbury, the firms appearing on page one capture the enquiry. Most local law firms have a single generic services page that fails to rank for any specific practice area plus location search. Each practice area you offer represents a distinct keyword cluster that requires dedicated content to rank."}, {"title": "Legal directories and comparison sites outranking your firm''s website", "description": "The Law Society, Solicitors.info, and legal comparison platforms invest heavily in SEO and dominate many general legal search terms. As a local firm, you cannot outspend these platforms nationally, but you can outrank them for specific local practice area searches where your dedicated, locally-focused content provides more relevant, detailed information."}, {"title": "No legal guide content building authority and capturing research-phase searches", "description": "Potential clients research legal processes extensively before choosing a solicitor. Searches like how long does conveyancing take, what happens during divorce proceedings, and how to contest a will represent people in the early stages of their legal journey. Without guide content targeting these research searches, you miss the opportunity to establish your firm as the trusted expert before the client starts comparing solicitors."}]',
  '[{"title": "Practice area landing pages optimised for local legal searches", "description": "Dedicated, optimised pages for every practice area your firm covers, each targeting location-specific search terms. Conveyancing, family law, wills and probate, personal injury, criminal defence, commercial law, and employment each receive comprehensive pages targeting their distinct search queries. This creates multiple ranking opportunities across your full service range."}, {"title": "Legal guide content building topical authority across practice areas", "description": "In-depth legal guides covering the processes, timescales, costs, and frequently asked questions for each practice area. Conveyancing process guides, divorce timeline explanations, and probate procedure walkthroughs attract research-phase traffic and build the topical authority that improves rankings across all your pages. Each guide positions your firm as knowledgeable local experts."}, {"title": "Google Business Profile optimisation for local Map Pack visibility", "description": "Your Google Business Profile optimised with accurate practice area categories, service area coverage, professional photography, and a review generation strategy. Legal searches heavily feature the Map Pack, and firms appearing in these three positions capture significant call volume. Regular Google Business posts maintain profile activity and signal relevance to the algorithm."}]',
  '[{"question": "How competitive is SEO for solicitors in Kent?", "answer": "General terms like solicitors near me are highly competitive, but practice-area-specific searches with location modifiers are achievable. A dedicated page targeting conveyancing solicitor Tunbridge Wells faces far less competition than a generic solicitor page. We build rankings across dozens of specific practice area and location combinations, creating cumulative visibility that generic approaches cannot match."}, {"question": "Should we create content explaining legal processes to potential clients?", "answer": "Absolutely. Legal guide content serves three purposes: it attracts research-phase traffic from people who will need a solicitor within weeks, it builds topical authority that improves rankings across all your pages, and it demonstrates the expertise that potential clients are looking for in their solicitor. A comprehensive conveyancing guide can rank for years and continuously attract your ideal clients."}, {"question": "How long before SEO generates new client instructions?", "answer": "Google Business Profile improvements can increase local visibility within four to six weeks. Practice area landing pages typically begin ranking within two to four months. Legal guide content builds compounding authority over six to twelve months. Most law firms see meaningful enquiry increases within three to four months, with sustained growth over the first year."}, {"question": "Can SEO help us compete with national legal directories for local searches?", "answer": "Yes. National directories produce generic content that cannot match the local detail, practice area depth, and client-specific information of a dedicated local firm''s website. By building comprehensive content for every practice area with local specificity, you establish relevance and authority that generic directory listings cannot replicate for your specific service area."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 3. Solicitors × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'solicitors',
  'lead-capture',
  'People contacting a solicitor are often in emotionally charged situations. A homeowner whose property chain is at risk of collapsing needs urgent conveyancing support. Someone served with divorce papers needs immediate family law guidance. A business owner facing an employment tribunal needs to understand their position quickly. These potential clients are anxious, time-sensitive, and evaluating whether your firm can help them based on how easily and quickly they can make initial contact. Most solicitor websites offer a phone number and a generic contact form that asks for a name, email, and message. This approach fails because it provides no structure for the visitor to explain their situation, no immediate response confirming their enquiry has been received, and no indication of what happens next. Lead capture for solicitors must provide practice-area-specific enquiry pathways that capture the relevant details for each legal matter, deliver immediate automated responses that acknowledge the enquiry and set expectations for response time, and route each enquiry to the appropriate fee earner based on practice area. A conveyancing enquiry should capture property details, transaction type, and timeline. A family law enquiry should capture the nature of the matter and urgency level. Each pathway provides the right experience for each client type.',
  'Law firms lose potential clients at the first contact stage more than any other point in the client journey. An enquiry that receives no response for twenty-four hours is often an enquiry lost to a competitor. A generic response that fails to acknowledge the client''s specific legal matter feels impersonal and undermines trust. The first interaction with your firm shapes the entire client relationship, and a slow or impersonal response starts that relationship poorly.',
  'We build practice-area-specific lead capture that guides potential clients through an appropriate initial enquiry process. Conveyancing forms capture property and transaction details. Family law forms assess matter type and urgency. Commercial enquiries identify business size and legal need. Automated responses are tailored to each practice area with relevant next-step information.',
  '[{"title": "Generic contact forms providing no structure for legal enquiries", "description": "A form asking for name, email, and message gives an anxious potential client no framework for explaining their situation. They either write an essay that your team must decode, or they write three words that tell you nothing. Neither outcome leads to an efficient first interaction. Without practice-area-specific forms, every enquiry requires a manual qualification conversation."}, {"title": "No automated acknowledgement leaving potential clients anxious about whether you received their message", "description": "Someone who has just been served with divorce papers or received a threatening letter sends an enquiry to your firm and hears nothing. For hours, they do not know if you received their message, if you handle their type of matter, or when someone will contact them. This silence creates anxiety that drives them to contact additional firms, reducing your conversion rate."}, {"title": "Enquiries not routed to the appropriate fee earner based on practice area", "description": "When all enquiries land in a shared inbox, a conveyancing matter sits alongside a criminal defence enquiry and a commercial dispute. The receptionist or office manager must read each one, determine the appropriate practice area, and forward it to the right solicitor. This manual triage adds delay and risks enquiries being misrouted or overlooked during busy periods."}]',
  '[{"title": "Practice-area-specific enquiry forms capturing relevant case details", "description": "Separate enquiry pathways for each practice area capture the information relevant to that legal matter. Conveyancing forms collect property address, transaction type, chain status, and mortgage position. Family law forms identify the matter type, urgency, and whether children are involved. Each form provides the relevant fee earner with enough information to prepare a meaningful initial response."}, {"title": "Immediate automated responses tailored to each practice area", "description": "Every enquiry receives an instant acknowledgement specific to their practice area. A conveyancing enquiry receives information about your conveyancing process and typical timescales. A family law enquiry receives guidance about initial consultation arrangements and what to bring. This practice-specific response demonstrates competence and care before any human interaction occurs."}, {"title": "Intelligent routing to fee earners with urgency-based prioritisation", "description": "Enquiries are automatically routed to the appropriate department or fee earner based on practice area. Urgency indicators within the form trigger priority flagging. Criminal matters, urgent family applications, and time-sensitive commercial disputes are escalated immediately. This ensures every enquiry reaches the right person quickly without manual triage."}]',
  '[{"question": "Can the forms be specific enough for different legal matters?", "answer": "Yes. Each practice area has its own form pathway with questions tailored to that legal service. Conveyancing forms capture different information from family law forms, which capture different details from commercial dispute forms. This specificity ensures you receive the relevant details for each matter type without requiring a preliminary phone call."}, {"question": "How do the automated responses work for different practice areas?", "answer": "Each practice area has a tailored automated response that acknowledges the enquiry and provides relevant initial information. A conveyancing response outlines your process and typical timescales. A family law response explains initial consultation arrangements. A commercial response confirms your team will review their matter. Each response feels personal and practice-specific rather than generic."}, {"question": "Can the system book initial consultation appointments directly?", "answer": "Yes. For practice areas where you offer initial consultations, the form can include appointment booking functionality integrated with your fee earners'' diaries. Potential clients select available consultation slots, receive confirmation, and arrive prepared with the information gathered during the form process. This accelerates the client onboarding journey."}, {"question": "How does urgency-based routing work?", "answer": "Form questions include urgency indicators relevant to each practice area. Criminal matters with court dates, family matters involving immediate safeguarding concerns, and commercial disputes with filing deadlines are flagged as urgent. These enquiries bypass standard routing and are delivered directly to the relevant fee earner with priority notification."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 4. Solicitors × Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'solicitors',
  'business-automation',
  'Law firms operate under regulatory requirements that create administrative demands unlike any other professional service. SRA compliance obligations include client account management, complaints handling procedures, continuing competence requirements, and transparency reporting. Anti-money-laundering regulations demand identity verification, source of funds checks, and risk assessments for every new client matter. GDPR imposes data protection obligations across every client file. And between managing compliance, fee earners are drowning in client onboarding paperwork, file opening procedures, correspondence management, and billing administration that erodes the time available for fee-earning work. Business automation for solicitors systematises the repeatable processes that consume your administrative capacity. New client onboarding workflows guide clients through identity verification, engagement letter signing, and initial information gathering without manual chasing. Matter milestones trigger automated client updates at key stages. AML check processes are standardised and documented. Time recording reminders ensure fee earners capture every billable unit. File review dates and limitation periods are tracked automatically. The compliance burden that currently requires dedicated administrative staff is handled systematically, reducing risk while freeing fee earners to focus on the legal work that generates revenue.',
  'Solicitors typically spend twenty to thirty percent of their working week on administration rather than billable work. For a fee earner charging two hundred pounds per hour, that represents thousands of pounds in unbilled time every month. Beyond the financial cost, manual compliance processes create risk: a missed AML check, a forgotten limitation date, or an overdue file review can trigger SRA intervention. Automation reduces both the financial cost and the compliance risk simultaneously.',
  'We automate around the specific regulatory and operational requirements of legal practice. Client onboarding workflows incorporate AML identity verification, engagement letter distribution, and initial document collection. Matter stage milestones trigger client update communications. SRA compliance tracking ensures transparency obligations, complaints procedures, and competence requirements are met systematically.',
  '[{"title": "Client onboarding consuming hours of manual administration per new matter", "description": "Opening a new client matter involves identity verification, source of funds documentation, conflict checks, engagement letter preparation and signing, initial information gathering, and file creation. Each step requires manual chasing, and a single new matter can take your support staff several hours of administrative work before the fee earner has even begun the legal work."}, {"title": "AML compliance processes inconsistent and poorly documented across fee earners", "description": "Anti-money-laundering regulations require documented identity verification, source of funds evidence, and risk assessments for every client. When each fee earner handles AML checks differently, with varying levels of documentation and different thresholds for enhanced due diligence, the firm''s compliance position is inconsistent and vulnerable to regulatory scrutiny."}, {"title": "Client updates falling behind because fee earners are focused on legal work", "description": "Clients expect regular updates about their matter, and the SRA expects firms to communicate effectively with clients. But when fee earners are absorbed in casework, client update calls and emails drop to the bottom of the priority list. Clients who feel uninformed become unhappy clients, and unhappy clients generate complaints that consume more time than proactive updates would have required."}]',
  '[{"title": "Automated client onboarding with integrated AML verification", "description": "New client workflows guide clients through identity verification via digital document submission, engagement letter e-signing, initial questionnaire completion, and key document upload. AML checks follow a standardised process with documented evidence collection and risk assessment scoring. The entire onboarding process runs with minimal manual intervention while maintaining full compliance documentation."}, {"title": "Matter milestone communications keeping clients informed automatically", "description": "Key stages in each matter type trigger automated client updates. Conveyancing clients receive updates when searches are ordered, when results return, and when exchange approaches. Family law clients receive stage updates as proceedings progress. These communications keep clients informed without fee earners manually writing routine update emails at every milestone."}, {"title": "SRA compliance tracking and regulatory obligation management", "description": "Automated tracking of SRA transparency requirements, complaints handling timelines, file review schedules, and continuing competence obligations. The system monitors compliance deadlines across the firm, alerts responsible individuals when action is required, and maintains an audit trail demonstrating systematic regulatory compliance. This reduces the risk of compliance oversights that trigger SRA intervention."}]',
  '[{"question": "Can automation handle the client identification and AML process?", "answer": "Yes. The system guides clients through digital identity document submission, captures source of funds declarations, and applies standardised risk assessment criteria. Enhanced due diligence triggers are built into the workflow based on matter type and risk indicators. Every step is documented and stored against the client file, providing a clear compliance audit trail."}, {"question": "How do automated client updates work for different practice areas?", "answer": "Each practice area has defined milestones that trigger client communications. Conveyancing milestones include search orders, search results, draft contracts, exchange, and completion. Family law milestones track petition filing, acknowledgement, and decree stages. The communications are tailored to each stage and practice area, providing relevant information without generic messaging."}, {"question": "Can the system track SRA compliance obligations across the whole firm?", "answer": "Yes. The system monitors transparency rule compliance, complaints handling timelines, annual renewal requirements, and continuing competence obligations for individual solicitors. Dashboard views show firm-wide compliance status. Alerts are triggered when deadlines approach or actions are overdue, providing the practice manager with oversight without manual diary tracking."}, {"question": "Will automation integrate with our existing case management system?", "answer": "We integrate with popular legal case management platforms including Clio, Leap, PracticePanther, and others. Where integration APIs are available, automation workflows connect to your existing system so client data, matter stages, and document management flow between the automation layer and your case management system without double entry."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
