-- 5. Solicitors × Branding
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'solicitors',
  'branding',
  'The legal profession exists in a branding paradox: solicitors must project authority and expertise while simultaneously being approachable to people who may be intimidated by the legal process. A brand that is too corporate and formal feels inaccessible to the divorcing parent, the first-time homebuyer, or the injured worker who needs legal help but is nervous about engaging a solicitor. A brand that is too casual undermines the gravitas expected of professionals handling matters with life-changing consequences. Most law firm branding defaults to conservative navy blue, serif fonts, and stock imagery of scales of justice and courtroom gavels. This generic legal aesthetic makes one firm visually indistinguishable from another, which means clients choose based on proximity or price rather than trust and affinity. Your brand should reflect the specific character of your firm: whether you are a high-street practice serving the local community or a specialist firm focused on particular practice areas. It should communicate competence without intimidation, tradition without stuffiness, and professionalism without coldness. We create brand identities for solicitors that establish the right tone for your firm, work across physical offices, digital platforms, and client-facing documentation, and differentiate your practice in a sector where visual conformity is the norm.',
  'Potential clients judge law firms on perceived competence and approachability before they ever speak to a solicitor. Your brand shapes that perception across every touchpoint: your website, your office frontage, your business cards, your correspondence, and your social media presence. In a profession where firms offer similar services at similar rates, brand perception is often the deciding factor. A distinctive, appropriate brand identity attracts clients who feel that your firm understands their situation.',
  'We design law firm brands that balance authority with approachability. Typography communicates professionalism without feeling corporate. Colour palettes differentiate your firm from the generic legal navy. Office signage, stationery, and digital assets create a cohesive identity. Client-facing document templates maintain brand standards across every interaction.',
  '[{"title": "Brand identity indistinguishable from every other local law firm", "description": "Navy blue colour scheme, serif typeface, and a generic scales-of-justice icon. This describes the majority of law firm branding in any town. When every firm looks identical, potential clients have no visual basis for differentiation. Your choice of solicitor feels arbitrary because no firm has established a distinctive identity that communicates their specific character and values."}, {"title": "Office presentation not matching the quality of legal service delivered", "description": "A law firm with excellent solicitors but dated signage, worn reception furniture, and inconsistent interior branding creates a disconnect between service quality and perceived quality. Clients visiting your office for the first time form impressions that shape their entire relationship with your firm. An office that looks outdated suggests a practice that has not kept pace."}, {"title": "Client-facing documents lacking professional brand consistency", "description": "Engagement letters, advice letters, cost estimates, and invoices that use different formatting, inconsistent logos, and varying styles undermine the professional image your brand should reinforce at every interaction. When a client receives five documents from your firm and each looks slightly different, it suggests an organisational inconsistency that erodes confidence."}]',
  '[{"title": "Distinctive brand identity balancing legal authority with approachability", "description": "A brand identity designed specifically for your firm''s character and target client base. Colour palettes that differentiate you from generic legal branding while maintaining professional gravitas. Typography that communicates competence without feeling intimidating. Visual elements that reflect your firm''s personality whether that is traditional and established or modern and progressive."}, {"title": "Office signage and interior branding creating a consistent client experience", "description": "External signage reflecting your brand identity and visible to local foot traffic. Reception area branding with consistent colours, materials, and presentation. Meeting room branding that provides a professional backdrop for client consultations. The physical environment reinforces the same brand qualities communicated by your website and documentation."}, {"title": "Client-facing document templates maintaining brand standards", "description": "Branded templates for every document type: engagement letters, advice letters, cost estimates, invoices, completion statements, and client care letters. Each template maintains your brand standards while meeting SRA requirements for content and presentation. Document consistency reinforces the professional, organised image that builds client confidence throughout their matter."}]',
  '[{"question": "How do you make a solicitor brand approachable without losing professionalism?", "answer": "The balance comes from design choices: warmer colour accents alongside authoritative base tones, modern typefaces that are clean and readable rather than stiff and traditional, and imagery that features real people and situations rather than legal cliches. The brand should feel like a confident, knowledgeable professional who also happens to be a genuinely helpful human being."}, {"question": "Should our branding look different depending on our practice areas?", "answer": "Your core brand identity should be consistent, but the expression can adapt across practice areas. A family law section might use warmer, more empathetic imagery while a commercial department uses more structured, corporate presentation. The colour palette, typography, and core identity remain consistent while the tone adapts to each audience''s expectations."}, {"question": "How important is office branding for a solicitor practice?", "answer": "Very. Clients visit your office during significant life events and form lasting impressions. A professionally branded reception, meeting room, and office environment reinforces the competence and attention to detail they expect from their solicitor. The physical experience should match the quality of your digital presence and the service your fee earners deliver."}, {"question": "Can you design branded templates that meet SRA documentation requirements?", "answer": "Yes. All document templates incorporate required SRA information including firm authorisation details, complaints procedures, and regulatory information while maintaining your brand standards. The templates ensure every letter, email, and document that leaves your firm is both compliant and professionally branded."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
